{"code": "import json
import re
from collections import defaultdict

# Load all data
books_file = locals()['var_functions.query_db:26']
reviews_file = locals()['var_functions.query_db:22']

with open(books_file, 'r') as f:
    books = json.load(f)

with open(reviews_file, 'r') as f:
    reviews = json.load(f)

# Extract years - simpler regex to catch all 4-digit numbers
books_with_years = []
year_regex = re.compile(r'\d{4}')

for book in books:
    details = str(book.get('details', ''))
    year_matches = year_regex.findall(details)

    valid_years = []
    for year_str in year_matches:
        year = int(year_str)
        if 1900 <= year <= 2023:
            valid_years.append(year)

    if valid_years:
        pub_year = max(valid_years)
        book_copy = dict(book)
        book_copy['publication_year'] = pub_year
        book_copy['decade'] = f"{pub_year//10*10}s"
        books_with_years.append(book_copy)

# Create numeric ID mapping for both books and reviews
book_numeric_map = {}
for book in books_with_years:
    book_id = book['book_id']
    if isinstance(book_id, str) and 'bookid_' in book_id:
        num_part = book_id.replace('bookid_', '')
        if num_part.isdigit():
            numeric_id = int(num_part)
            book_numeric_map[numeric_id] = book['decade']

# Group reviews by decade
decade_groups = defaultdict(lambda: {'ratings': [], 'books': set()})
for review in reviews:
    purchase_id = review.get('purchase_id')
    rating_str = review.get('rating')

    if purchase_id and rating_str:
        if isinstance(purchase_id, str) and 'purchaseid_' in purchase_id:
            num_part = purchase_id.replace('purchaseid_', '')
            if num_part.isdigit():
                numeric_id = int(num_part)
                if numeric_id in book_numeric_map:
                    try:
                        rating = float(rating_str)
                        if 1 <= rating <= 5:
                            decade = book_numeric_map[numeric_id]
                            decade_groups[decade]['ratings'].append(rating)
                            decade_groups[decade]['books'].add(numeric_id)
                    except:
                        pass

# Calculate decade statistics (minimum 10 distinct books)
decade_results = []
for decade, data in decade_groups.items():
    num_books = len(data['books'])
    if num_books >= 10:
        avg_rating = sum(data['ratings']) / len(data['ratings'])
        decade_results.append({
            'decade': decade,
            'average_rating': round(avg_rating, 3),
            'review_count': len(data['ratings']),
            'book_count': num_books
        })

# Sort by average rating descending
decade_results.sort(key=lambda x: x['average_rating'], reverse=True)

# Format final answer
if decade_results:
    winner = decade_results[0]['decade']
else:
    winner = "None found"

print('__RESULT__:')
print(json.dumps({
    'winner_decade': winner,
    'decade_rankings': decade_results,
    'stats': {
        'total_books': len(books),
        'books_with_years': len(books_with_years),
        'total_reviews': len(reviews),
        'books_matched': len(book_numeric_map),
        'decades_with_10plus_books': len(decade_results)
    }
}))"}

